import React, { useState, useRef, useEffect } from 'react';
import { Plus, ArrowUp, X, Sparkles, ChevronLeft, Camera, Upload, File, Edit3, Copy, Check, Trash2, RotateCcw, MoreVertical, Save, FileText } from 'lucide-react';

const STATES = {
  INPUT: 'input',
  GENERATING: 'generating',
  REVIEW: 'review',
  ANALYSIS_OVERVIEW: 'analysis_overview',
  ANALYSIS_SECTION: 'analysis_section'
};

const MOCK_SECTIONS = [
  {
    id: 'context',
    name: 'Role & Context',
    content: 'You are an expert customer feedback analyst with 10+ years of experience in SaaS product development.',
    subsections: [
      { id: 'role', name: 'Role Definition', content: 'Expert customer feedback analyst' },
      { id: 'expertise', name: 'Expertise Level', content: '10+ years experience in SaaS' }
    ]
  },
  {
    id: 'objective',
    name: 'Task & Objective',
    content: 'Analyze customer feedback to identify sentiment patterns, extract key themes, and group findings by product feature area.',
    subsections: [
      { id: 'main-action', name: 'Primary Action', content: 'Analyze customer feedback' },
      { id: 'deliverables', name: 'Key Deliverables', content: 'Sentiment patterns, themes, feature groupings' }
    ]
  },
  {
    id: 'process',
    name: 'Process & Steps',
    content: 'Review each feedback entry, categorize by feature area, identify recurring themes, calculate sentiment scores.',
    subsections: []
  },
  {
    id: 'rules',
    name: 'Rules & Constraints',
    content: 'Focus on factual observations, avoid speculation, maintain objectivity in sentiment scoring.',
    subsections: []
  },
  {
    id: 'output',
    name: 'Output Format',
    content: 'Provide results as bullet points grouped by feature area. Include sentiment score (1-5) and top 3 themes per feature.',
    subsections: [
      { id: 'structure', name: 'Response Structure', content: 'Bullet points grouped by feature' },
      { id: 'metrics', name: 'Key Metrics', content: 'Sentiment score (1-5), top 3 themes' }
    ]
  },
  {
    id: 'examples',
    name: 'Examples',
    content: 'Example: For "Login is confusing" â†’ Feature: Authentication, Sentiment: 2/5, Theme: UX complexity.',
    subsections: []
  }
];

const PromptBuilderV7 = () => {
  const [currentState, setCurrentState] = useState(STATES.INPUT);
  const [inputText, setInputText] = useState('');
  const [inputChatMode, setInputChatMode] = useState(false);
  const [inputChatMessages, setInputChatMessages] = useState([]);

  const [activeSections, setActiveSections] = useState([]);
  const [savedSections, setSavedSections] = useState([]);
  const [generatedPrompt, setGeneratedPrompt] = useState('');

  // Selection state
  const [selectedSectionId, setSelectedSectionId] = useState(null);
  const [clickedOnce, setClickedOnce] = useState(null); // Track first click for double-click pattern
  const [focusedSection, setFocusedSection] = useState(null); // When drilled into section
  const [highlightedSubsection, setHighlightedSubsection] = useState(null);
  const [highlightedSection, setHighlightedSection] = useState(false);

  // Edit states
  const [editMode, setEditMode] = useState(false);
  const [editContent, setEditContent] = useState('');
  const [copiedMessage, setCopiedMessage] = useState(false);
  const [showMenu, setShowMenu] = useState(false);

  // Chat state
  const [chatMode, setChatMode] = useState(false);
  const [chatMessages, setChatMessages] = useState([]);
  const [chatInput, setChatInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  const [uploadedFiles, setUploadedFiles] = useState({ overview: [], sections: {} });
  const [showUploadMenu, setShowUploadMenu] = useState(false);
  const [isRegenerating, setIsRegenerating] = useState(false);

  const chatInputRef = useRef(null);
  const chatEndRef = useRef(null);
  const fileInputRef = useRef(null);

  useEffect(() => {
    if (chatMode && chatEndRef.current) {
      chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatMessages, chatMode]);

  const handleGenerate = () => {
    // Get the input either from direct text or from chat messages
    let input = inputText;
    if (inputChatMode && inputChatMessages.length > 0) {
      // Get all user messages to build context
      const userMessages = inputChatMessages
        .filter(m => m.role === 'user')
        .map(m => m.content)
        .join(' ');
      input = userMessages || inputText;
    }

    if (!input.trim()) return;

    setCurrentState(STATES.GENERATING);

    setTimeout(() => {
      // Intelligently select relevant sections based on input
      const inputLower = input.toLowerCase();
      const selectedSections = [];

      // Always include Role & Context and Task & Objective (core sections)
      selectedSections.push(MOCK_SECTIONS[0]); // Role & Context
      selectedSections.push(MOCK_SECTIONS[1]); // Task & Objective

      // Add Process & Steps if input mentions process/steps/workflow
      if (inputLower.includes('process') || inputLower.includes('step') || 
          inputLower.includes('workflow') || inputLower.includes('how')) {
        selectedSections.push(MOCK_SECTIONS[2]);
      }

      // Add Rules & Constraints if input mentions rules/constraints/limit/must/should not
      if (inputLower.includes('rule') || inputLower.includes('constraint') || 
          inputLower.includes('limit') || inputLower.includes('must') || 
          inputLower.includes('should not') || inputLower.includes('avoid')) {
        selectedSections.push(MOCK_SECTIONS[3]);
      }

      // Add Output Format if input mentions output/format/structure
      if (inputLower.includes('output') || inputLower.includes('format') || 
          inputLower.includes('structure') || inputLower.includes('provide') || 
          inputLower.includes('return')) {
        selectedSections.push(MOCK_SECTIONS[4]);
      }

      // Add Examples if input mentions example/sample/like/such as
      if (inputLower.includes('example') || inputLower.includes('sample') || 
          inputLower.includes('like') || inputLower.includes('such as') || 
          inputLower.includes('instance')) {
        selectedSections.push(MOCK_SECTIONS[5]);
      }

      // If no optional sections matched, default to Output Format
      if (selectedSections.length === 2) {
        selectedSections.push(MOCK_SECTIONS[4]); // Output Format
      }

      setActiveSections(selectedSections);
      setSavedSections(JSON.parse(JSON.stringify(selectedSections)));

      const fullPrompt = selectedSections.map(s => s.content).join('\n\n');
      setGeneratedPrompt(fullPrompt);

      // Reset input state
      setInputText('');
      setInputChatMode(false);
      setInputChatMessages([]);

      setCurrentState(STATES.REVIEW);
    }, 1500);
  };

  const enterAnalysis = () => {
    setSavedSections(JSON.parse(JSON.stringify(activeSections)));
    setCurrentState(STATES.ANALYSIS_OVERVIEW);
  };

  const exitAnalysis = () => {
    setCurrentState(STATES.REVIEW);
    setSelectedSectionId(null);
    setClickedOnce(null);
    setFocusedSection(null);
    setChatMode(false);
    setChatMessages([]);
  };

  const revertChanges = () => {
    setActiveSections(JSON.parse(JSON.stringify(savedSections)));
    setGeneratedPrompt(savedSections.map(s => s.content).join('\n\n'));
    setSelectedSectionId(null);
    setClickedOnce(null);
  };

  const handleSectionClick = (sectionId) => {
    if (clickedOnce === sectionId) {
      // Second click - drill in
      setFocusedSection(sectionId);
      setCurrentState(STATES.ANALYSIS_SECTION);
      setClickedOnce(null);
      setSelectedSectionId(null);
    } else {
      // First click - highlight
      setClickedOnce(sectionId);
      setSelectedSectionId(sectionId);
      setTimeout(() => setClickedOnce(null), 2000); // Reset after 2s
    }
  };

  const backToOverview = () => {
    setCurrentState(STATES.ANALYSIS_OVERVIEW);
    setFocusedSection(null);
    setHighlightedSubsection(null);
    setHighlightedSection(false);
    setEditMode(false);
    setChatMode(false);
    setChatMessages([]);
  };

  const toggleEditMode = () => {
    if (!editMode) {
      setEditContent(generatedPrompt);
    }
    setEditMode(!editMode);
  };

  const saveManualEdit = () => {
    setGeneratedPrompt(editContent);

    // If in analysis mode, try to update sections based on edited content
    if (currentState === STATES.ANALYSIS_OVERVIEW && activeSections.length > 0) {
      // Split edited content by section names to maintain structure
      const updatedSections = [...activeSections];
      updatedSections.forEach((section, idx) => {
        // Try to extract this section's content from edited text
        const sectionStart = editContent.indexOf(section.content.substring(0, 50));
        if (sectionStart !== -1) {
          const nextSectionStart = idx < updatedSections.length - 1 
            ? editContent.indexOf(updatedSections[idx + 1].content.substring(0, 50))
            : editContent.length;

          if (nextSectionStart > sectionStart) {
            section.content = editContent.substring(sectionStart, nextSectionStart).trim();
          }
        }
      });
      setActiveSections(updatedSections);
    }

    setEditMode(false);
  };

  const copyPrompt = () => {
    navigator.clipboard.writeText(generatedPrompt);
    setCopiedMessage(true);
    setTimeout(() => setCopiedMessage(false), 2000);
  };

  const handleMenuAction = (action) => {
    setShowMenu(false);

    switch(action) {
      case 'save':
        // TODO: Implement save functionality
        alert('Save functionality coming soon!');
        break;
      case 'templates':
        // TODO: Implement templates view
        alert('Templates view coming soon!');
        break;
      case 'delete':
        if (confirm('Delete current prompt and start over?')) {
          setCurrentState(STATES.INPUT);
          setInputText('');
          setActiveSections([]);
          setGeneratedPrompt('');
          setSavedSections([]);
          setSelectedSectionId(null);
          setEditMode(false);
        }
        break;
    }
  };

  const handleFileUpload = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const fileData = {
      name: file.name,
      type: file.type,
      size: file.size
    };

    if (!focusedSection) {
      setUploadedFiles(prev => ({
        ...prev,
        overview: [...prev.overview, fileData]
      }));
    } else {
      setUploadedFiles(prev => ({
        ...prev,
        sections: {
          ...prev.sections,
          [focusedSection]: [...(prev.sections[focusedSection] || []), fileData]
        }
      }));
    }
    setShowUploadMenu(false);
  };

  const handleTakePhoto = () => {
    console.log('Camera not implemented');
    setShowUploadMenu(false);
  };

  const handleQuickAction = (action) => {
    setIsRegenerating(true);

    setTimeout(() => {
      let newContent = '';

      if (highlightedSubsection && focusedSection) {
        const section = activeSections.find(s => s.id === focusedSection);
        const subsection = section?.subsections?.find(s => s.id === highlightedSubsection);
        const currentContent = subsection?.content || '';

        if (action === 'expand') {
          newContent = currentContent + ' with comprehensive details and analysis';
        } else if (action === 'condense') {
          newContent = currentContent.split(' ').slice(0, 3).join(' ');
        }

        const updatedSections = activeSections.map(s => {
          if (s.id === focusedSection) {
            const updatedSubsections = (s.subsections || []).map(sub =>
              sub.id === highlightedSubsection ? { ...sub, content: newContent } : sub
            );
            const newSectionContent = updatedSubsections.map(sub => sub.content).join('. ') + '.';
            return {
              ...s,
              subsections: updatedSubsections,
              content: newSectionContent
            };
          }
          return s;
        });
        setActiveSections(updatedSections);
        setGeneratedPrompt(updatedSections.map(s => s.content).join('\n\n'));

      } else if (highlightedSection && focusedSection) {
        const section = activeSections.find(s => s.id === focusedSection);
        const currentContent = section?.content || '';

        if (action === 'expand') {
          newContent = currentContent + ' This includes comprehensive analysis.';
        } else if (action === 'condense') {
          newContent = currentContent.split('.')[0] + '.';
        }

        const updatedSections = activeSections.map(s =>
          s.id === focusedSection ? { ...s, content: newContent } : s
        );
        setActiveSections(updatedSections);
        setGeneratedPrompt(updatedSections.map(s => s.content).join('\n\n'));
      }

      setIsRegenerating(false);
    }, 600);
  };

  const handleSendMessage = () => {
    if (!chatInput.trim()) return;

    const userMessage = chatInput;
    setChatInput('');

    setChatMessages(prev => [...prev, {
      role: 'user',
      content: userMessage
    }]);

    setIsProcessing(true);

    setTimeout(() => {
      let currentContent = '';
      let updatedContent = '';
      let aiResponse = '';

      if (highlightedSubsection && focusedSection) {
        const section = activeSections.find(s => s.id === focusedSection);
        const subsection = section?.subsections?.find(s => s.id === highlightedSubsection);
        currentContent = subsection?.content || '';
      } else if (highlightedSection && focusedSection) {
        currentContent = activeSections.find(s => s.id === focusedSection)?.content || '';
      }

      if (userMessage.toLowerCase().includes('longer') || userMessage.toLowerCase().includes('expand')) {
        updatedContent = currentContent + ' with additional context';
        aiResponse = 'Made it longer.';
      } else if (userMessage.toLowerCase().includes('shorter') || userMessage.toLowerCase().includes('condense')) {
        updatedContent = currentContent.split('.')[0] + '.';
        aiResponse = 'Condensed it.';
      } else {
        updatedContent = currentContent + ` [${userMessage}]`;
        aiResponse = 'Updated.';
      }

      if (highlightedSubsection && focusedSection) {
        const updatedSections = activeSections.map(s => {
          if (s.id === focusedSection) {
            const updatedSubsections = (s.subsections || []).map(sub =>
              sub.id === highlightedSubsection ? { ...sub, content: updatedContent } : sub
            );
            const newSectionContent = updatedSubsections.map(sub => sub.content).join('. ') + '.';
            return {
              ...s,
              subsections: updatedSubsections,
              content: newSectionContent
            };
          }
          return s;
        });
        setActiveSections(updatedSections);
        setGeneratedPrompt(updatedSections.map(s => s.content).join('\n\n'));
      } else if (highlightedSection && focusedSection) {
        const updatedSections = activeSections.map(s =>
          s.id === focusedSection ? { ...s, content: updatedContent } : s
        );
        setActiveSections(updatedSections);
        setGeneratedPrompt(updatedSections.map(s => s.content).join('\n\n'));
      }

      setChatMessages(prev => [...prev, {
        role: 'assistant',
        content: aiResponse
      }]);

      setIsProcessing(false);
    }, 800);
  };

  const toggleChatMode = () => {
    setChatMode(!chatMode);
    if (!chatMode) {
      setChatMessages([{
        role: 'system',
        content: 'What would you like to change?'
      }]);
      setTimeout(() => chatInputRef.current?.focus(), 100);
    }
  };

  const toggleInputChatMode = () => {
    setInputChatMode(!inputChatMode);
    if (!inputChatMode) {
      setInputChatMessages([{
        role: 'system',
        content: 'Tell me about your prompt. What do you need help building?'
      }]);
      setTimeout(() => chatInputRef.current?.focus(), 100);
    }
  };

  const handleInputChatMessage = () => {
    if (!inputText.trim()) return;

    const userMessage = inputText;
    setInputText('');

    setInputChatMessages(prev => [...prev, {
      role: 'user',
      content: userMessage
    }]);

    setIsProcessing(true);

    // Mock AI response to help build prompt
    setTimeout(() => {
      let aiResponse = `I can help you build that prompt. Based on what you described, I'll create a structured prompt with:

â€¢ Role & Context
â€¢ Task & Objective  
â€¢ Output Format

Would you like me to generate it now? Or would you like to add more details?`;

      setInputChatMessages(prev => [...prev, {
        role: 'assistant',
        content: aiResponse
      }]);

      setIsProcessing(false);
    }, 800);
  };

  const addNewSection = () => {
    if (activeSections.length >= 6) return;

    // Find sections from MOCK_SECTIONS that aren't currently active
    const currentIds = activeSections.map(s => s.id);
    const availableSections = MOCK_SECTIONS.filter(s => !currentIds.includes(s.id));

    let newSection;
    if (availableSections.length > 0) {
      // Add first available standard section
      newSection = availableSections[0];
    } else {
      // All standard sections present, create custom one
      newSection = {
        id: `section-${Date.now()}`,
        name: 'Custom Section',
        content: 'Enter content for this section.',
        subsections: []
      };
    }

    const updatedSections = [...activeSections, newSection];
    setActiveSections(updatedSections);
    setGeneratedPrompt(updatedSections.map(s => s.content).join('\n\n'));
  };

  const deleteSection = (sectionId) => {
    const updatedSections = activeSections.filter(s => s.id !== sectionId);
    setActiveSections(updatedSections);
    setGeneratedPrompt(updatedSections.map(s => s.content).join('\n\n'));
  };

  const renderContent = () => {
    if (currentState === STATES.INPUT) {
      return (
        <div className="h-full flex flex-col">
          <div className="text-gray-400 text-sm mb-6 flex-shrink-0">
            What do you want to build?
          </div>

          {!inputChatMode ? (
            <textarea
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              className="flex-1 bg-transparent text-white placeholder-gray-600 text-base leading-relaxed resize-none border-none focus:outline-none"
              placeholder="Example: I need to analyze customer feedback and identify common themes..."
              autoFocus
            />
          ) : (
            <div className="flex-1 overflow-y-auto space-y-3 pr-2">
              {inputChatMessages.map((msg, idx) => (
                <div 
                  key={idx}
                  className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  <div className={`
                    max-w-[80%] rounded-2xl px-4 py-3 text-sm
                    ${msg.role === 'user'
                      ? 'bg-cyan-500 text-white'
                      : msg.role === 'system'
                        ? 'bg-gray-800/60 text-gray-400 border border-gray-700'
                        : 'bg-gray-800 text-gray-200'
                    }
                  `}>
                    {msg.content}
                  </div>
                </div>
              ))}
              {isProcessing && (
                <div className="flex justify-start">
                  <div className="bg-gray-800 rounded-2xl px-4 py-3">
                    <div className="flex gap-1">
                      <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay: '0ms'}} />
                      <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay: '150ms'}} />
                      <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay: '300ms'}} />
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      );
    }

    if (currentState === STATES.GENERATING) {
      return (
        <div className="h-full flex flex-col items-center justify-center">
          <div className="w-12 h-12 border-2 border-cyan-500 border-t-transparent rounded-full animate-spin mb-4" />
          <div className="text-gray-400 text-sm">Structuring your prompt...</div>
        </div>
      );
    }

    if (currentState === STATES.REVIEW || currentState === STATES.ANALYSIS_OVERVIEW) {
      return (
        <div className="h-full overflow-y-auto">
          <div className="relative">
            {/* Main prompt box */}
            <div className={`
              bg-gray-800/40 rounded-xl p-5 border transition-all
              ${editMode ? 'border-cyan-500' : 'border-gray-700'}
            `}>
              {currentState === STATES.ANALYSIS_OVERVIEW ? (
                // Analysis mode - sections are clickable with separators
                <div className="space-y-4">
                  {activeSections.map((section, idx) => (
                    <div key={section.id}>
                      {idx > 0 && <div className="border-t border-gray-700/50 my-4" />}
                      <div
                        onClick={() => handleSectionClick(section.id)}
                        className={`
                          relative cursor-pointer transition-all rounded-lg p-3 -mx-3
                          ${selectedSectionId === section.id
                            ? 'bg-cyan-500/10 border border-cyan-500/30'
                            : 'hover:bg-gray-800/40'
                          }
                        `}
                      >
                        <div className="text-xs text-cyan-400 mb-2 font-medium">{section.name}</div>
                        <div className="text-white text-sm leading-relaxed">{section.content}</div>

                        {/* Delete button - appears when section is highlighted */}
                        {selectedSectionId === section.id && (
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              deleteSection(section.id);
                              setSelectedSectionId(null);
                              setClickedOnce(null);
                            }}
                            className="absolute top-3 right-3 p-1.5 bg-gray-900/80 hover:bg-red-600 rounded-lg transition-colors"
                            title="Delete section"
                          >
                            <Trash2 className="w-3.5 h-3.5 text-gray-400 hover:text-white" />
                          </button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                // Review mode - editable or plain text
                editMode ? (
                  <textarea
                    value={editContent}
                    onChange={(e) => setEditContent(e.target.value)}
                    className="w-full bg-transparent text-white text-sm leading-relaxed resize-none border-none focus:outline-none min-h-[300px]"
                    autoFocus
                  />
                ) : (
                  <div className="text-white text-sm leading-relaxed whitespace-pre-wrap">
                    {generatedPrompt}
                  </div>
                )
              )}

              {/* Copy + Edit buttons - bottom center */}
              <div className="flex justify-center gap-2 mt-6 pt-4 border-t border-gray-700/30">
                {editMode ? (
                  <>
                    <button
                      onClick={() => setEditMode(false)}
                      className="px-4 py-2 text-sm text-gray-400 hover:text-white transition-colors"
                    >
                      Cancel
                    </button>
                    <button
                      onClick={saveManualEdit}
                      className="px-4 py-2 text-sm bg-cyan-500 hover:bg-cyan-600 text-white rounded-lg transition-colors flex items-center gap-1.5"
                    >
                      <Check className="w-4 h-4" />
                      Save
                    </button>
                  </>
                ) : (
                  <>
                    <button
                      onClick={copyPrompt}
                      className="flex items-center gap-1.5 px-3 py-1.5 text-xs text-gray-400 hover:text-cyan-400 bg-gray-800/60 hover:bg-gray-800 rounded-lg transition-colors"
                    >
                      <Copy className="w-3.5 h-3.5" />
                      <span>{copiedMessage ? 'Copied!' : 'Copy'}</span>
                    </button>
                    {/* Edit button only in REVIEW mode, not in ANALYSIS_OVERVIEW */}
                    {currentState === STATES.REVIEW && (
                      <button
                        onClick={toggleEditMode}
                        className="flex items-center gap-1.5 px-3 py-1.5 text-xs text-gray-400 hover:text-cyan-400 bg-gray-800/60 hover:bg-gray-800 rounded-lg transition-colors"
                      >
                        <Edit3 className="w-3.5 h-3.5" />
                        <span>Edit</span>
                      </button>
                    )}
                  </>
                )}
              </div>
            </div>

            {/* Section management - only in analysis mode */}
            {currentState === STATES.ANALYSIS_OVERVIEW && !editMode && (
              <div className="mt-6 flex items-center justify-center gap-3">
                <div className="text-xs text-gray-500">
                  {activeSections.length} of 6 sections
                </div>

                <button
                  onClick={addNewSection}
                  disabled={activeSections.length >= 6}
                  className={`
                    px-4 py-2 border border-dashed rounded-lg text-xs transition-all flex items-center gap-1.5
                    ${activeSections.length >= 6
                      ? 'border-gray-800 text-gray-600 cursor-not-allowed'
                      : 'border-gray-700 hover:border-cyan-500/50 text-gray-500 hover:text-cyan-400'
                    }
                  `}
                >
                  <Plus className="w-4 h-4" />
                  {activeSections.length >= 6 ? 'Max reached' : 'Add Section'}
                </button>
              </div>
            )}
          </div>
        </div>
      );
    }

    if (currentState === STATES.ANALYSIS_SECTION) {
      // Section detail view (existing functionality)
      const section = activeSections.find(s => s.id === focusedSection);
      if (!section) return null;

      return (
        <div className="h-full overflow-y-auto space-y-4 pr-2">
          {/* Quick actions */}
          <div className="grid grid-cols-2 gap-2">
            <button 
              onClick={() => handleQuickAction('expand')}
              disabled={isRegenerating || (!highlightedSection && !highlightedSubsection)}
              className="py-3 bg-gray-800/40 hover:bg-gray-800/60 border border-gray-700 rounded-lg text-sm text-gray-300 hover:text-cyan-400 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Expand
            </button>
            <button 
              onClick={() => handleQuickAction('condense')}
              disabled={isRegenerating || (!highlightedSection && !highlightedSubsection)}
              className="py-3 bg-gray-800/40 hover:bg-gray-800/60 border border-gray-700 rounded-lg text-sm text-gray-300 hover:text-cyan-400 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Condense
            </button>
          </div>

          {/* Main section content */}
          <div 
            onClick={() => setHighlightedSection(!highlightedSection)}
            className={`
              relative bg-gray-800/60 rounded-xl p-5 border transition-all cursor-pointer
              ${highlightedSection
                ? 'border-cyan-500 bg-cyan-500/10'
                : 'border-gray-700 hover:border-gray-600'
              }
            `}
          >
            <div className="text-white text-base leading-relaxed">
              {section.content}
            </div>
          </div>

          {/* Subsections */}
          {section.subsections && section.subsections.length > 0 ? (
            <div className="space-y-2">
              <div className="text-xs text-gray-500 uppercase tracking-wider">Components</div>
              {section.subsections.map((subsection) => (
                <button
                  key={subsection.id}
                  onClick={() => {
                    setHighlightedSubsection(subsection.id === highlightedSubsection ? null : subsection.id);
                    setHighlightedSection(false);
                  }}
                  className={`
                    w-full text-left rounded-lg p-3 transition-all
                    ${highlightedSubsection === subsection.id
                      ? 'bg-cyan-500/20 border-2 border-cyan-500'
                      : 'bg-gray-800/40 hover:bg-gray-800/60 border border-gray-700'
                    }
                  `}
                >
                  <div className="text-gray-300 text-sm mb-1">{subsection.name}</div>
                  <div className="text-gray-500 text-xs">{subsection.content}</div>
                </button>
              ))}
            </div>
          ) : (
            <div className="text-center py-4 text-xs text-gray-600">
              No sub-components for this section
            </div>
          )}

          {/* Chat */}
          {chatMode && (
            <div className="space-y-3 max-h-[40vh] overflow-y-auto">
              <div className="text-xs text-gray-500 uppercase tracking-wider">Chat with Claude</div>

              {chatMessages.map((msg, idx) => (
                <div 
                  key={idx}
                  className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  <div className={`
                    max-w-[80%] rounded-2xl px-4 py-3 text-sm
                    ${msg.role === 'user'
                      ? 'bg-cyan-500 text-white'
                      : msg.role === 'system'
                        ? 'bg-gray-800/60 text-gray-400 border border-gray-700'
                        : 'bg-gray-800 text-gray-200'
                    }
                  `}>
                    {msg.content}
                  </div>
                </div>
              ))}

              {isProcessing && (
                <div className="flex justify-start">
                  <div className="bg-gray-800 rounded-2xl px-4 py-3">
                    <div className="flex gap-1">
                      <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay: '0ms'}} />
                      <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay: '150ms'}} />
                      <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay: '300ms'}} />
                    </div>
                  </div>
                </div>
              )}
              <div ref={chatEndRef} />
            </div>
          )}
        </div>
      );
    }

    return null;
  };

  const getButtonConfig = () => {
    if (currentState === STATES.INPUT) {
      const hasContent = inputText.trim() || (inputChatMode && inputChatMessages.some(m => m.role === 'user'));

      return {
        left: { 
          icon: inputChatMode ? X : Sparkles,
          action: toggleInputChatMode,
          active: inputChatMode
        },
        center: { 
          icon: ArrowUp, 
          action: handleGenerate,
          disabled: !hasContent
        },
        right: { icon: Camera, action: () => setShowUploadMenu(true) }
      };
    }

    if (currentState === STATES.REVIEW) {
      return {
        left: { icon: Sparkles, action: enterAnalysis },
        center: { icon: Plus, disabled: true },
        right: { icon: Camera, action: () => setShowUploadMenu(true) }
      };
    }

    if (currentState === STATES.ANALYSIS_OVERVIEW) {
      return {
        left: { icon: ChevronLeft, action: exitAnalysis },
        center: { icon: Plus, disabled: true },
        right: { icon: Camera, action: () => setShowUploadMenu(true) }
      };
    }

    if (currentState === STATES.ANALYSIS_SECTION) {
      return {
        left: { icon: ChevronLeft, action: backToOverview },
        center: { 
          icon: chatMode ? X : Sparkles,
          action: toggleChatMode,
          active: chatMode
        },
        right: { icon: Camera, action: () => setShowUploadMenu(true) }
      };
    }

    return {
      left: { icon: Plus, disabled: true },
      center: { icon: ArrowUp, disabled: true },
      right: { icon: X, disabled: true }
    };
  };

  const buttons = getButtonConfig();

  return (
    <div className="h-screen flex flex-col bg-gradient-to-b from-gray-900 via-black to-gray-900">
      {/* Header */}
      <div className="flex justify-between items-center p-4 border-b border-gray-800/50">
        <div className="flex items-center gap-3">
          <div className="text-white font-medium tracking-tight">PromptEngine</div>
          {(currentState === STATES.ANALYSIS_OVERVIEW || currentState === STATES.ANALYSIS_SECTION) && (
            <button
              onClick={revertChanges}
              className="flex items-center gap-1.5 px-2.5 py-1 text-xs text-gray-400 hover:text-cyan-400 bg-gray-800/60 hover:bg-gray-800 rounded-lg transition-colors"
              title="Revert all changes"
            >
              <RotateCcw className="w-3.5 h-3.5" />
              <span>Revert</span>
            </button>
          )}
        </div>
        <div className="flex items-center gap-3">
          <div className="text-xs px-2 py-1 rounded-full text-gray-500">
            {currentState === STATES.ANALYSIS_OVERVIEW && 'analysis'}
            {currentState === STATES.ANALYSIS_SECTION && 'section'}
            {currentState === STATES.REVIEW && 'review'}
            {currentState === STATES.INPUT && 'input'}
          </div>

          {/* Three-dot menu */}
          <div className="relative">
            <button
              onClick={() => setShowMenu(!showMenu)}
              className="p-1.5 text-gray-400 hover:text-cyan-400 hover:bg-gray-800/60 rounded-lg transition-colors"
              title="Menu"
            >
              <MoreVertical className="w-4 h-4" />
            </button>

            {showMenu && (
              <>
                {/* Backdrop */}
                <div 
                  className="fixed inset-0 z-10"
                  onClick={() => setShowMenu(false)}
                />

                {/* Dropdown */}
                <div className="absolute right-0 mt-2 w-48 bg-gray-800 border border-gray-700 rounded-lg shadow-xl z-20 overflow-hidden">
                  <button
                    onClick={() => handleMenuAction('save')}
                    className="w-full flex items-center gap-3 px-4 py-3 text-sm text-gray-300 hover:bg-gray-700/50 transition-colors text-left"
                  >
                    <Save className="w-4 h-4" />
                    <span>Save Prompt</span>
                  </button>
                  <button
                    onClick={() => handleMenuAction('templates')}
                    className="w-full flex items-center gap-3 px-4 py-3 text-sm text-gray-300 hover:bg-gray-700/50 transition-colors text-left border-t border-gray-700/50"
                  >
                    <FileText className="w-4 h-4" />
                    <span>View Templates</span>
                  </button>
                  <button
                    onClick={() => handleMenuAction('delete')}
                    className="w-full flex items-center gap-3 px-4 py-3 text-sm text-red-400 hover:bg-red-500/10 transition-colors text-left border-t border-gray-700/50"
                  >
                    <Trash2 className="w-4 h-4" />
                    <span>Delete & Restart</span>
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      </div>

      {/* Main content */}
      <div className="flex-1 px-6 py-6 overflow-hidden flex flex-col">
        {renderContent()}
      </div>

      {/* Chat input */}
      {currentState === STATES.INPUT && inputChatMode && (
        <div className="px-6 pb-4">
          <input
            ref={chatInputRef}
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleInputChatMessage()}
            placeholder="Type your message..."
            className="w-full bg-gray-800 text-white placeholder-gray-500 rounded-xl px-4 py-3 text-sm border border-gray-700 focus:border-cyan-500 focus:outline-none"
          />
        </div>
      )}

      {currentState === STATES.ANALYSIS_SECTION && chatMode && (
        <div className="px-6 pb-4">
          <input
            ref={chatInputRef}
            type="text"
            value={chatInput}
            onChange={(e) => setChatInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
            placeholder="Type your request..."
            className="w-full bg-gray-800 text-white placeholder-gray-500 rounded-xl px-4 py-3 text-sm border border-gray-700 focus:border-cyan-500 focus:outline-none"
          />
        </div>
      )}

      {/* Bottom prompt text */}
      <div className="px-6 pb-8 pt-4">
        <div className="text-center text-gray-500 text-sm mb-6">
          {currentState === STATES.INPUT && !inputChatMode && 'Describe what you need, or tap sparkle to chat'}
          {currentState === STATES.INPUT && inputChatMode && 'Chatting about your prompt'}
          {currentState === STATES.REVIEW && 'Tap sparkle to analyze'}
          {currentState === STATES.ANALYSIS_OVERVIEW && 'Click section once to highlight, twice to edit'}
          {currentState === STATES.ANALYSIS_SECTION && !chatMode && 'Tap sparkle to chat'}
          {currentState === STATES.ANALYSIS_SECTION && chatMode && 'Chatting with Claude'}
        </div>

        {/* Three-button nav */}
        <div className="flex justify-center items-center gap-8">
          <button
            onClick={buttons.left.action}
            disabled={buttons.left.disabled}
            className={`
              w-14 h-14 rounded-full flex items-center justify-center transition-all active:scale-95
              ${buttons.left.disabled 
                ? 'opacity-30 cursor-not-allowed bg-gray-800/80 border border-gray-700/50'
                : 'bg-gray-800/80 hover:bg-gray-800 border border-gray-700/50'
              }
            `}
          >
            {buttons.left.icon && <buttons.left.icon className="w-5 h-5 text-gray-400" />}
          </button>

          <button
            onClick={buttons.center.action}
            disabled={buttons.center.disabled}
            className={`
              w-16 h-16 rounded-full flex items-center justify-center shadow-lg transition-all active:scale-95
              ${buttons.center.disabled
                ? 'opacity-30 cursor-not-allowed bg-gray-800/80'
                : buttons.center.active 
                  ? 'bg-cyan-500 hover:bg-cyan-600' 
                  : 'bg-white hover:bg-gray-100'
              }
            `}
          >
            {buttons.center.icon && (
              <buttons.center.icon className={`w-6 h-6 ${buttons.center.active ? 'text-white' : 'text-black'}`} />
            )}
          </button>

          <button
            onClick={buttons.right.action}
            disabled={buttons.right.disabled}
            className="w-14 h-14 rounded-full bg-gray-800/80 hover:bg-gray-800 border border-gray-700/50 flex items-center justify-center transition-all active:scale-95"
          >
            {buttons.right.icon && <buttons.right.icon className="w-5 h-5 text-gray-400" />}
          </button>
        </div>
      </div>

      {/* Upload menu */}
      {showUploadMenu && (
        <div 
          className="absolute inset-0 bg-black/60 backdrop-blur-sm flex items-end"
          onClick={() => setShowUploadMenu(false)}
        >
          <div 
            className="w-full bg-gray-900 rounded-t-3xl p-6 space-y-3 animate-slide-up"
            onClick={(e) => e.stopPropagation()}
          >
            <button
              onClick={() => {
                fileInputRef.current?.click();
                setShowUploadMenu(false);
              }}
              className="w-full flex items-center gap-4 p-4 bg-gray-800 hover:bg-gray-700 rounded-xl transition-colors"
            >
              <div className="w-10 h-10 rounded-full bg-cyan-500/20 flex items-center justify-center">
                <Upload className="w-5 h-5 text-cyan-400" />
              </div>
              <div className="text-left">
                <div className="text-white text-sm font-medium">Upload File</div>
                <div className="text-xs text-gray-400">Add document or image</div>
              </div>
            </button>

            <button
              onClick={handleTakePhoto}
              className="w-full flex items-center gap-4 p-4 bg-gray-800 hover:bg-gray-700 rounded-xl transition-colors"
            >
              <div className="w-10 h-10 rounded-full bg-cyan-500/20 flex items-center justify-center">
                <Camera className="w-5 h-5 text-cyan-400" />
              </div>
              <div className="text-left">
                <div className="text-white text-sm font-medium">Take Photo</div>
                <div className="text-xs text-gray-400">Capture with camera</div>
              </div>
            </button>

            <button
              onClick={() => setShowUploadMenu(false)}
              className="w-full py-3 text-gray-400 text-sm"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      <input
        ref={fileInputRef}
        type="file"
        onChange={handleFileUpload}
        accept="image/*,.pdf,.doc,.docx,.txt"
        className="hidden"
      />

      <style jsx>{`
        @keyframes slide-up {
          from { transform: translateY(100%); }
          to { transform: translateY(0); }
        }
        .animate-slide-up {
          animation: slide-up 0.3s ease-out;
        }
      `}</style>
    </div>
  );
};

export default PromptBuilderV7;

/*
 * V7 - UNIFIED FLOW (COMPLETE)
 * 
 * Key features:
 * - Single box throughout (no separate cards or views)
 * - Same background (no theme transitions)
 * - Copy + Edit buttons always present (bottom center of box)
 * - Double-click pattern: first click highlights, second drills
 * 
 * States:
 * - INPUT: Type or chat with AI to build prompt
 *   - Sparkle button toggles AI chat mode
 *   - Can discuss prompt requirements with AI
 *   - Upload button active for reference files
 * 
 * - REVIEW: Single box with full prompt text
 *   - Copy button (with "Copied!" feedback)
 *   - Edit button (inline editing, not separate view)
 *   - Sparkle enters analysis
 * 
 * - ANALYSIS_OVERVIEW: Same box, sections become interactive
 *   - Sections separated with dividers
 *   - Click once â†’ highlights section
 *   - Click again (within 2s) â†’ drills into detail
 *   - Add/delete sections via pills below box
 *   - Revert button in header
 * 
 * - ANALYSIS_SECTION: Detail view for selected section
 *   - Quick actions (Expand/Condense) on highlighted elements
 *   - Main box clickable to highlight
 *   - Subsections clickable to highlight
 *   - Chat with sparkle button
 *   - Back returns to overview
 * 
 * Dynamic section generation:
 * - Only creates relevant sections based on input
 * - Core sections always included: Role & Context, Task & Objective
 * - Optional sections added based on keywords:
 *   - Process & Steps: if mentions "process", "step", "workflow", "how"
 *   - Rules & Constraints: if mentions "rule", "constraint", "must", "avoid"
 *   - Output Format: if mentions "output", "format", "provide"
 *   - Examples: if mentions "example", "sample", "like"
 * - Defaults to 3 sections minimum
 * - Max 6 sections total
 * 
 * Section management:
 * - Add button cycles through missing standard sections first
 * - Then allows custom sections if all 6 standard exist
 * - Delete removes any section (even if "needed")
 * - Re-adding deleted section restores original content
 * 
 * Edit modes:
 * 1. Inline edit (review/analysis) - box becomes editable textarea
 * 2. Quick actions - Expand/Condense on highlighted elements
 * 3. Chat - AI-assisted editing via natural language
 * 
 * Upload menu:
 * - Camera button opens bottom sheet
 * - Upload File or Take Photo options
 * - Files scoped to current context
 */
